import React from 'react';

const StockMovementForm = ({ refreshMovements, updateProductQuantity, isEditing, currentMovementId, movement, products }) => {
    const handleChange = (e) => {
        // Lógica para lidar com as mudanças no formulário
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        // Lógica para submeter a movimentação
    };

    return (
        <form onSubmit={handleSubmit}>
            <select name="produto" value={movement.produto} onChange={handleChange} required>
                <option value="">Selecione um produto</option>
                {products.map((product) => (
                    <option key={product.id} value={product.id}>
                        {product.nome}
                    </option>
                ))}
            </select>
            <select name="tipo_movimentacao" value={movement.tipo_movimentacao} onChange={handleChange}>
                <option value="entrada">Entrada</option>
                <option value="saida">Saída</option>
            </select>
            <input
                type="number"
                name="quantidade"
                value={movement.quantidade}
                onChange={handleChange}
                placeholder="Quantidade"
                required
            />
            <textarea
                name="motivo"
                value={movement.motivo}
                onChange={handleChange}
                placeholder="Motivo (opcional)"
            />
            <button type="submit">{isEditing ? 'Atualizar' : 'Adicionar'}</button>
        </form>
    );
};

export default StockMovementForm;
